#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int maxProfit(vector<int>& prices) {
        long long buy1 = -1e18, sell1 = 0;
        long long buy2 = -1e18, sell2 = 0;
        for (int price : prices) {
            buy1 = max(buy1, (long long)-price);
            sell1 = max(sell1, buy1 + price);
            buy2 = max(buy2, sell1 - price);
            sell2 = max(sell2, buy2 + price);
        }
        return sell2;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> prices(n);
    for (int i = 0; i < n; i++) cin >> prices[i];
    Solution sol;
    int ans = sol.maxProfit(prices);
    cout << ans << "\n";
    return 0;
}
